SELECT name AS name, description AS description
FROM subject
WHERE name = #{type}

SELECT user_id AS userId
FROM user
WHERE user_id = #{id} AND password = #{pw}

mapper.update:
UPDATE user 
SET PASSWORD = #{updatePw} 
WHERE user_id = #{id} AND PASSWORD = #{currentPw}

mapper.insert:
INSERT INTO payment (enrollment_id, amount, paid_at)
SELECT enrollment_id, #{amount}, NOW()
FROM student_enrollment
WHERE lecture_id = #{lectureId}
  AND student_id = #{studentId}
  AND status = 'PAID'

mapper.update:
UPDATE student_enrollment
SET status = 'PAID'
WHERE lecture_id = #{lectureId}
	AND student_id = #{studentId}
	AND status = 'PENDING'

mapper.select:
SELECT album_id, lecture_id, title, description, created_at FROM album
WHERE title LIKE CONCAT('%', #{keyword}, '%')
ORDER BY created_at DESC LIMIT #{startRow}, #{rowPerPage}

SELECT COUNT(*)
FROM student_enrollment
WHERE student_id = #{studentId} 
AND lecture_id = #{lectureId}
AND status != 'CANCEL'

mapper.update:
UPDATE student_enrollment
SET status = 'PENDING'
WHERE student_id = #{studentId}
	AND lecture_id = #{lectureId}
	AND status = 'CANCEL'

		UPDATE student_enrollment
        SET status = 'CANCEL'
        WHERE lecture_id = #{lectureId}
        	AND student_id = #{studentId}
        	AND status = #{status}

		UPDATE student_enrollment se
		JOIN lecture l ON se.lecture_id = l.lecture_id
        SET se.status = 'REFUNDWAIT'
        WHERE se.lecture_id = #{lectureId}
        	AND se.student_id = #{studentId}
        	AND se.status = #{status}
        	AND l.start_date >= DATE_ADD(CURDATE(), INTERVAL 3 DAY)
